        throw new Error("Invalid 'entryCount'. It must be a non-negative integer.");
    }

    // 2. Security: Sanitize the file path to prevent Command Injection.
    // We wrap the path in single quotes and escape any single quotes inside the path.
    const sanitizedPath = "'" + logFilePath.replace(/'/g, "'\\''") + "'";

    // 3. Construct the command pipeline as specified in the requirements.
    const command = `grep 'ERROR' ${sanitizedPath} | tail -n 100 | awk '{print $1,$2,$0}' | sort | tail -n ${count}`;

    // 4. Execute the command
    // silent: true prevents the output from being printed to the parent console.
    const result = shell.exec(command, { silent: true });

    // 5. Handle execution results
    if (result.code !== 0) {
        // If grep returns exit code 1 (no matches), it might be masked by the pipeline.
        // But if it propagates or another error occurs:
        if (result.code === 1 && !result.stderr) {
            return [];
        }

        // If there is actual error output, throw an exception.
        throw new Error(`Command execution failed: ${result.stderr}`);
    }

    const stdout = result.stdout;

    // Handle empty output (no errors found)
    if (!stdout || stdout.trim() === '') {
        return [];
    }

    // Convert the output string into an array of lines
    return stdout.trim().split('\n');
}

module.exports = { extractRecentErrors };
